prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT CONCAT(STR(?start),'|',STR(?end))) AS ?pathCount) WHERE {
  {
    SELECT DISTINCT ?start ?end WHERE {
      ?model a bboExt:Model ;
             tai:originalId "3c08e52742754da6a4065fc5787131dc" .
      ?def tai:belongsTo ?model .
      ?choreo a bboExt:Choreography ;
              tai:belongsTo ?def .

      ?start a bboExt:StartEvent ;
             tai:belongsTo ?choreo ;
             bbo:name ?startName .
      ?end a bboExt:EndEvent ;
           tai:belongsTo ?choreo ;
           bbo:name ?endName .

      FILTER( ?startName != "" && ?endName != "" )

      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?end .

      FILTER NOT EXISTS {
        ?mid a bboExt:EndEvent ;
             tai:belongsTo ?choreo ;
             bbo:name ?midName .
        FILTER(?mid != ?end)
        ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?mid .
      }
    }
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?start ?startName ?end ?endName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?end a bboExt:EndEvent ;
       tai:belongsTo ?choreo .
  OPTIONAL { ?end bbo:name ?endName . }
}
LIMIT 25

